#include <iostream>
#include <string>

struct Employee
{
    std::string name;
    int id;
};

Employee* findById(Employee employees[], int size, int targetId)
{
    for (int i{ 0 }; i < size; ++i)
    {
        if (employees[i].id == targetId)
            return &employees[i];
    }
    return nullptr;
}

int main()
{
    int n{};
    std::cin >> n;

    Employee employees[10];
    for (int i{ 0 }; i < n; ++i)
    {
        std::cin >> employees[i].name >> employees[i].id;
    }

    int queryId{};
    std::cin >> queryId;

    Employee* result{ findById(employees, n, queryId) };
    if (result != nullptr)
        std::cout << "Found: " << result->name << " (ID: " << result->id << ")\n";
    else
        std::cout << "Not found\n";

    return 0;
}

